import{k as e,p as t,u as n}from"./chunks/runtime-core.esm-bundler.PK8HO-US.js";import{t as r}from"./chunks/plugin-vue_export-helper.DrfHhw6c.js";import{i,n as a,r as o,t as s}from"./chunks/windows-wizard-screenshot.QBlzzreT.js";const c=JSON.parse(`{"title":"Instalando Java no Windows","description":"Um guia passo a passo de como instalar o Java no Windows.","frontmatter":{"title":"Instalando Java no Windows","description":"Um guia passo a passo de como instalar o Java no Windows.","authors":["IMB11","skycatminepokie"],"next":false,"files":[]},"headers":[],"relativePath":"pt_br/players/installing-java/windows.md","filePath":"translated/pt_br/players/installing-java/windows.md","lastUpdated":1770561656000}`);var l={name:`pt_br/players/installing-java/windows.md`};function u(r,i,a,o,s,c){return e(),n(`div`,null,[...i[0]||=[t(`<h1 id="h1" tabindex="-1">Instalando Java no Windows <a class="header-anchor" href="#h1" aria-label="Permalink to “Instalando Java no Windows”">​</a></h1><p>Este guia o orientará na instalação do Java 17 no Windows.</p><p>O Launcher do Minecraft vem com sua própria instalação do Java, portanto esta seção só é relevante se você quiser usar o instalador baseado em <code>.jar</code> do Fabric ou se quiser usar o <code>.jar</code> do Servidor do Minecraft.</p><h2 id="_1-verificar-se-o-java-ja-esta-instalado" tabindex="-1">1. Verificar Se o Java Já Está Instalado <a class="header-anchor" href="#_1-verificar-se-o-java-ja-esta-instalado" aria-label="Permalink to “1. Verificar Se o Java Já Está Instalado”">​</a></h2><p>Para verificar se o Java já está instalado, você deve primeiro abrir o prompt de comando.</p><p>Você pode fazer isso pressionando <kbd>Windows</kbd>+<kbd>R</kbd> e digitando <code>cmd.exe</code> na caixa que aparecerá.</p><p><img src="/assets/players/installing-java/windows-run-dialog.png" alt="Caixa de diálogo Executar do Windows com &quot;cmd.exe&quot; na barra de execução" loading="lazy"></p><p>Após abrir o prompt de comando, digite <code>java -version</code> e pressione <kbd>Enter</kbd>.</p><p>Se o comando for executado com êxito, você verá algo parecido com isto. Se o comando falhar, prossiga para o próximo passo.</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Prompt de comando com &quot;java -version&quot; digitado" loading="lazy"></p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Para usar o Minecraft 1.21.11, você precisará ter, pelo menos, o Java 21 instalado.</p><p>Se esse comando exibir qualquer versão inferior a 21, você precisará atualizar o seu Java; continue lendo essa página.</p></div><h2 id="2-download-the-java-installer" tabindex="-1">2. Baixar o instalador do Java 21 <a class="header-anchor" href="#2-download-the-java-installer" aria-label="Permalink to “2. Baixar o instalador do Java 21”">​</a></h2><p>Para instalar o Java 21, você precisará baixar o instalador direto do <a href="https://adoptium.net/temurin/releases?version=21&amp;os=windows&amp;arch=any&amp;mode=filter" target="_blank" rel="noreferrer">Adoptium</a>.</p><p>Você precisará baixar a versão do <code>Windows Installer (.msi)</code>:</p><p><img src="/assets/players/installing-java/windows-download-java.png" alt="Página para baixar o Adoptium com Windows Installer (.msi) highlighted" loading="lazy"></p><p>Você deverá escolher <code>x86</code> se você tiver um sistema 32-bit ou <code>x64</code> se você tiver um sistema 64-bit.</p><p>A vasta maioria dos computadores modernos terão um sistema 64-bit. Se você não tiver certeza, tente baixar o instalador para 64-bit.</p><h2 id="3-run-the-installer" tabindex="-1">3. Execute o instalador! <a class="header-anchor" href="#3-run-the-installer" aria-label="Permalink to “3. Execute o instalador!”">​</a></h2><p>Siga as instruções para instalar o Java 21. Quando você chegar até essa página, você deve configurar os seguintes recursos para &quot;Todos os recursos serão instalados no Disco Local&quot;:</p><ul><li><code>Set JAVA_HOME environment variable</code> - Isso será adicionado ao diretório PATH.</li><li><code>JavaSoft (Oracle) registry keys</code></li></ul><p><img src="/assets/players/installing-java/windows-wizard-screenshot.png" alt="O Instalador de Java 21 &quot;Set JAVA_HOME variable&quot; e as Chaves de Registro &quot;JavaSoft (Oracle)&quot; destacadas" loading="lazy"></p><p>Uma vez que tenha feito isso, você pode clicar em <code>Next</code> e continuar com a Instalação.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>Nem sempre o Windows dirá para outros programas que o Java está instalado, pelo menos até que o computador seja reiniciado.</p><p><strong>Certifique-se de reiniciar o seu computador antes de continuar!</strong></p></div><h2 id="4-verify-that-java-is-installed" tabindex="-1">4. Verificar se o Java 21 está instalado <a class="header-anchor" href="#4-verify-that-java-is-installed" aria-label="Permalink to “4. Verificar se o Java 21 está instalado”">​</a></h2><p>Uma que vez que a instalação esteja completa, você pode se certificar disso abrindo um terminal de comando e digitando <code>java -version</code>.</p><p>Se o comando for executado corretamente, você verá o que foi mostrado anteriormente, no local onde a versão do Java é mostrada:</p><p><img src="/assets/players/installing-java/windows-java-version.png" alt="Prompt de comando com &quot;java -version&quot; digitado" loading="lazy"></p><p>Se você encontrar problemas, sinta-se a vontade para pedir ajuda em <a href="https://discord.fabricmc.net/" target="_blank" rel="noreferrer">Discord do Fabric</a> no canal <code>#player-support</code>.</p>`,28)]])}var d=r(l,[[`render`,u]]);export{c as __pageData,d as default};